                            current = schema
                            for part in parts[:-1]:
                                if part in current and isinstance(current[part], dict):
                                    current = current[part]
                                else:
                                    current = {}
                                    break
                            if isinstance(current, dict) and parts[-1] in current:
                                decl = current[parts[-1]]
                                if isinstance(decl, dict) and 'type' in decl:
