    if watch_mode := True:  # Always true here
        if primary_params and primary_store_url:
            # Monitor primary store for changes
            # For each unique base key, set up a watch cursor
            # Since we can have multiple parameters using the same primary-store key,
            # we need to track changes per key and apply to all parameters using it
            primary_key_to_paths: dict[str, list[str]] = {}
            for path, pkey in primary_params.items():
