                        if key != pkey:
                            continue
                        if version <= key_versions[pkey]:
                            # Stale or duplicate - skip
                            continue

                        # Update the cursor to the latest version
                        key_versions[pkey] = version

                        # Apply the update to all tracked parameters
                        for param_path in tracked_paths:
